definition.script:
pipeline {
    agent { label "${params.AGENT_LABEL ?: 'local-security-agent'}" }
    options {
        buildDiscarder(logRotator(numToKeepStr: '20'))
        timeout(time: 60, unit: 'MINUTES')
    }
    environment {
        REGISTRY = "${params.REGISTRY_URL ?: '132.186.17.22:5000'}"
        SCAN_SEVERITY = 'CRITICAL,HIGH'
        SOURCE_DIR = ''
    }
    stages {
        stage('Setup') {
            steps {
                script {
                    sh 'mkdir -p security-reports'
                    sh 'echo "=== Tools ===" && trivy --version 2>&1 | head -1'

                    // Determine source directory
                    if (params.SOURCE_UPLOAD_PATH?.trim()) {
                        def uploadPath = params.SOURCE_UPLOAD_PATH.trim()
                        def tarFile = "${uploadPath}/source.tar.gz"
                        def srcDir = "${WORKSPACE}/user-source"
                        sh """
                            mkdir -p '${srcDir}'
                            if [ -f '${tarFile}' ]; then
                                tar xzf '${tarFile}' -C '${srcDir}' 2>/dev/null || true
                                echo "=== Source code extracted ==="
                                echo "Files: \$(find '${srcDir}' -type f | wc -l)"
                                echo "Size:  \$(du -sh '${srcDir}' | cut -f1)"
                            else
                                echo "WARNING: Source tar not found at ${tarFile}"
                            fi
                        """
                        env.SOURCE_DIR = srcDir
                    } else {
                        env.SOURCE_DIR = WORKSPACE
                    }

                    echo """
                    ==========================================
                      Security Scan Pipeline
                    ==========================================
                      Scan Type:   ${params.UNIFIED_SCAN_MODE ?: params.SCAN_TYPE}
                      Strict:      ${params.STRICT_MODE}
                      Scan ID:     ${params.SCAN_ID ?: 'N/A'}
                      Image:       ${env.REGISTRY}/${params.IMAGE_NAME}:${params.IMAGE_TAG}
                      Source Dir:  ${env.SOURCE_DIR}
                      Source Upload: ${params.SOURCE_UPLOAD_PATH ? 'YES (user code)' : 'NO'}
                    ==========================================
                    """
                }
            }
        }
        stage('Secret Detection') {
            when { expression { (params.UNIFIED_SCAN_MODE ?: params.SCAN_TYPE) in ['full', 'code-only'] } }
            steps {
                script {
                    def scanDir = env.SOURCE_DIR ?: WORKSPACE
                    sh "echo '=== Scanning for secrets in: ${scanDir} ==='"
                    sh "trivy fs --scanners secret --format json --output security-reports/secret-scan.json '${scanDir}' || true"
                    sh "trivy fs --scanners secret --format table '${scanDir}' || true"
                }
            }
        }
        stage('SAST / Vulnerability Scan') {
            when { expression { (params.UNIFIED_SCAN_MODE ?: params.SCAN_TYPE) in ['full', 'code-only'] } }
            steps {
                script {
                    def scanDir = env.SOURCE_DIR ?: WORKSPACE
                    sh "echo '=== SAST scan on: ${scanDir} ==='"
                    sh "trivy fs --scanners vuln,misconfig --severity CRITICAL,HIGH --format json --output security-reports/trivy-fs-scan.json '${scanDir}' || true"
                    sh "trivy fs --scanners vuln,misconfig --severity CRITICAL,HIGH --format table '${scanDir}' || true"
                }
            }
        }
        stage('SCA / Dependency Scan') {
            when { expression { (params.UNIFIED_SCAN_MODE ?: params.SCAN_TYPE) in ['full', 'code-only'] } }
            steps {
                script {
                    def scanDir = env.SOURCE_DIR ?: WORKSPACE
                    sh "echo '=== SCA dependency scan on: ${scanDir} ==='"
                    sh "trivy fs --scanners vuln --severity CRITICAL,HIGH,MEDIUM --format json --output security-reports/trivy-sca.json '${scanDir}' || true"
                    sh "trivy fs --scanners vuln --severity CRITICAL,HIGH,MEDIUM --format table --output security-reports/trivy-sca.txt '${scanDir}' || true"
                }
            }
        }
        stage('Image Scan') {
            when { expression { (params.UNIFIED_SCAN_MODE ?: params.SCAN_TYPE) in ['full', 'image-only'] } }
            steps {
                script {
                    def img = "${env.REGISTRY}/${params.IMAGE_NAME}:${params.IMAGE_TAG}"
                    sh "echo '=== Image scan: ${img} ==='"
                    sh "trivy image --podman-host '' --severity CRITICAL,HIGH --format json --output security-reports/trivy-image-scan.json '${img}' || true"
                    sh "trivy image --podman-host '' --severity CRITICAL,HIGH --format table --output security-reports/trivy-image-scan.txt '${img}' || true"
                }
            }
        }
        stage('K8s Manifest Scan') {
            when { expression { (params.UNIFIED_SCAN_MODE ?: params.SCAN_TYPE) in ['full', 'k8s-manifests'] } }
            steps {
                script {
                    // If user uploaded source with K8s manifests, scan those
                    def scanDir = env.SOURCE_DIR ?: WORKSPACE
                    // Look for yaml/yml files in uploaded source
                    def hasK8s = sh(script: "find '${scanDir}' -name '*.yaml' -o -name '*.yml' 2>/dev/null | head -1", returnStdout: true).trim()
                    if (hasK8s) {
                        sh "echo '=== K8s manifest scan on: ${scanDir} ==='"
                        sh "trivy config --severity CRITICAL,HIGH --format json --output security-reports/trivy-k8s-config.json '${scanDir}' || true"
                        sh "trivy config --severity CRITICAL,HIGH --format table --output security-reports/trivy-k8s-config.txt '${scanDir}' || true"
                    } else {
                        sh "echo 'No YAML/YML files found for K8s manifest scan'"
                    }
                }
            }
        }
        stage('Registry Scan') {
            when { expression { return params.SCAN_REGISTRY_IMAGES } }
            steps {
                script {
                    def registry = env.REGISTRY
                    sh """
                        echo "=== Scanning all images in registry: ${registry} ==="
                        REPOS=\$(curl -s http://${registry}/v2/_catalog | python3 -c "import sys,json; [print(r) for r in json.load(sys.stdin).get('repositories',[])]" 2>/dev/null || echo "")
                        for REPO in \$REPOS; do
                            TAGS=\$(curl -s http://${registry}/v2/\$REPO/tags/list | python3 -c "import sys,json; [print(t) for t in json.load(sys.stdin).get('tags',[])]" 2>/dev/null || echo "latest")
                            for TAG in \$TAGS; do
                                echo "--- Scanning \$REPO:\$TAG ---"
                                trivy image --podman-host '' --severity CRITICAL,HIGH --format table "${registry}/\$REPO:\$TAG" || true
                            done
                        done
                    """
                }
            }
        }
        stage('CycloneDX SBOM Generation') {
            when { expression { return params.GENERATE_SBOM } }
            steps {
                script {
                    echo '=== CycloneDX SBOM Generation ==='
                    sh 'mkdir -p security-reports/sbom'
                    def scanDir = env.SOURCE_DIR ?: WORKSPACE
                    // Trivy CycloneDX SBOM
                    sh "trivy fs --format cyclonedx --output security-reports/sbom/trivy-cyclonedx-sbom.json '${scanDir}' || true"
                    // Trivy SPDX SBOM (compliance cross-check)
                    sh "trivy fs --format spdx-json --output security-reports/sbom/trivy-spdx-sbom.json '${scanDir}' || true"
                    // Summary
                    sh """
                        if [ -f security-reports/sbom/trivy-cyclonedx-sbom.json ]; then
                            COMP_COUNT=\$(python3 -c "import json; d=json.load(open('security-reports/sbom/trivy-cyclonedx-sbom.json')); print(len(d.get('components',[])))" 2>/dev/null || echo '0')
                            echo "SBOM Components found: \${COMP_COUNT}"
                            echo "CycloneDX SBOM: security-reports/sbom/trivy-cyclonedx-sbom.json"
                            echo "SPDX SBOM:      security-reports/sbom/trivy-spdx-sbom.json"
                        else
                            echo 'WARNING: CycloneDX SBOM generation produced no output'
                        fi
                    """
                }
            }
        }
        stage('Security Gate') {
            steps {
                script {
                    echo '=== Security Gate ==='
                    def rc = sh(script: '''
                        CRIT=0
                        for f in security-reports/trivy-image-scan.json security-reports/trivy-fs-scan.json; do
                            if [ -f "$f" ]; then
                                C=$(python3 -c "import json; d=json.load(open('$f')); print(sum(1 for r in d.get('Results',[]) for v in r.get('Vulnerabilities',[]) if v.get('Severity')=='CRITICAL'))" 2>/dev/null || echo 0)
                                CRIT=$((CRIT + C))
                            fi
                        done
                        echo "CRITICAL vulnerabilities: $CRIT"
                        [ "$CRIT" -gt 0 ] && exit 1 || exit 0
                    ''', returnStatus: true)
                    if (rc != 0 && params.FAIL_ON_CRITICAL) {
                        unstable('CRITICAL vulnerabilities detected')
                    }
                }
            }
        }
    }
    post {
        always {
            archiveArtifacts artifacts: 'security-reports/**', allowEmptyArchive: true
            script {
                // Cleanup uploaded source code
                if (params.SOURCE_UPLOAD_PATH?.trim()) {
                    sh "rm -rf '${env.SOURCE_DIR}' 2>/dev/null || true"
                    // Signal cleanup to the HTTP server
                    if (params.SCAN_ID?.trim()) {
                        sh """
                            curl -s -X POST http://132.186.17.22:9091/cleanup \
                                -H 'Content-Type: application/json' \
                                -d '{"scan_id": "${params.SCAN_ID}"}' || true
                        """
                    }
                }
            }
            echo 'Security scan complete.'
        }
    }
}
